def _adls_container_to_nested(adls_container: ADLSContainer) -> ADLSContainerNested:
    """Convert flat ADLSContainer to nested format."""
    attrs = ADLSContainerAttributes()
    _populate_adls_container_attrs(attrs, adls_container)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        adls_container, _ADLS_CONTAINER_REL_FIELDS, ADLSContainerRelationshipAttributes
    )
    return ADLSContainerNested(
        guid=adls_container.guid,
        type_name=adls_container.type_name,
        status=adls_container.status,
        version=adls_container.version,
        create_time=adls_container.create_time,
        update_time=adls_container.update_time,
        created_by=adls_container.created_by,
        updated_by=adls_container.updated_by,
        classifications=adls_container.classifications,
        classification_names=adls_container.classification_names,
        meanings=adls_container.meanings,
        labels=adls_container.labels,
        business_attributes=adls_container.business_attributes,
        custom_attributes=adls_container.custom_attributes,
        pending_tasks=adls_container.pending_tasks,
        proxy=adls_container.proxy,
        is_incomplete=adls_container.is_incomplete,
        provenance_type=adls_container.provenance_type,
        home_id=adls_container.home_id,
        depth=adls_container.depth,
        immediate_upstream=adls_container.immediate_upstream,
        immediate_downstream=adls_container.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _adls_container_from_nested(nested: ADLSContainerNested) -> ADLSContainer:
    """Convert nested format to flat ADLSContainer."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else ADLSContainerAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _ADLS_CONTAINER_REL_FIELDS,
        ADLSContainerRelationshipAttributes,
    )
    return ADLSContainer(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_adls_container_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _adls_container_to_nested_bytes(
    adls_container: ADLSContainer, serde: Serde
) -> bytes:
    """Convert flat ADLSContainer to nested JSON bytes."""
    return serde.encode(_adls_container_to_nested(adls_container))


def _adls_container_from_nested_bytes(data: bytes, serde: Serde) -> ADLSContainer:
    """Convert nested JSON bytes to flat ADLSContainer."""
    nested = serde.decode(data, ADLSContainerNested)
    return _adls_container_from_nested(nested)


